70: ssl_ECPubKey2NamedGroup(const SECKEYPublicKey *pubKey)
71: {
72:     SECItem oid = { siBuffer, NULL, 0 };
73:     SECOidData *oidData = NULL;
74:     PRUint32 policyFlags = 0;
75:     unsigned int i;
